// Liquidación de nómina — v0.2 (dividida en funciones)

function calcBruto(empleado) {
  let bruto = empleado.salarioBase;
  if (empleado.horas > 40) {
    const extras = empleado.horas - 40;
    bruto = bruto + extras * empleado.tarifa * 1.5;
  }
  return bruto;
}

function calcDescuentos(bruto) {
  const salud = bruto * 0.04;
  const pension = bruto * 0.04;
  const retencion = bruto > 5000 ? bruto * 0.10 : 0;
  return { salud, pension, retencion, total: salud + pension + retencion };
}

function formatBoleta(empleado, bruto, descuentos, neto) {
  let boleta = '';
  boleta = boleta + 'Empleado: ' + empleado.nombre + '\\n';
  boleta = boleta + 'Bruto: $' + bruto.toFixed(2) + '\\n';
  boleta = boleta + 'Salud: $' + descuentos.salud.toFixed(2) + '\\n';
  boleta = boleta + 'Pensión: $' + descuentos.pension.toFixed(2) + '\\n';
  boleta = boleta + 'Retención: $' + descuentos.retencion.toFixed(2) + '\\n';
  boleta = boleta + 'Neto: $' + neto.toFixed(2) + '\\n';
  return boleta;
}

function calcularLiquidacion(empleado) {
  const bruto = calcBruto(empleado);
  const descuentos = calcDescuentos(bruto);
  const neto = bruto - descuentos.total;
  const boleta = formatBoleta(empleado, bruto, descuentos, neto);
  return { bruto, neto, descuentos: descuentos.total, boleta };
}

