const emp = { nombre: 'Ana', salarioBase: 3000, horas: 40, tarifa: 50 };
const r = calcularLiquidacion(emp);
const bruto = 3000;
const desc = bruto * 0.04 * 2;
const esperado = bruto - desc;
if (Math.abs(r.neto - esperado) > 0.01)
  throw new Error(`Esperado ${esperado}, recibido ${r.neto}`);

const emp = { nombre: 'Beto', salarioBase: 6000, horas: 40, tarifa: 50 };
const r = calcularLiquidacion(emp);
const bruto = 6000;
const desc = bruto * 0.04 * 2 + bruto * 0.10;
const esperado = bruto - desc;
if (Math.abs(r.neto - esperado) > 0.01)
  throw new Error(`Esperado ${esperado}, recibido ${r.neto}`);

const emp = { nombre: 'Carla', salarioBase: 2000, horas: 35, tarifa: 40 };
const r = calcularLiquidacion(emp);
if (!r.boleta.includes('Carla'))
  throw new Error('La boleta debe incluir el nombre del empleado');
